<div class="module-page form-grid"><section class="glass-card form-card"><h3>Registrar calidad del agua</h3><form method="POST" class="stack-form" action="<?= e(page_url('encargado-calidad-agua')) ?>"><?= csrf_field() ?><select name="idAlberca" class="form-select"><?php foreach($p as $pool): ?><option value="<?= e($pool['idAlberca']) ?>"><?= e($pool['nombre']) ?></option><?php endforeach; ?></select><input class="form-control" name="cloro_ppm" type="number" step="0.01" placeholder="Cloro ppm" required><input class="form-control" name="ph" type="number" step="0.01" placeholder="pH" required><input class="form-control" name="temperatura_c" type="number" step="0.1" placeholder="Temperatura °C" required><textarea class="form-control" name="observaciones" placeholder="Observaciones"></textarea><button class="btn btn-aqua">Guardar</button></form></section><section class="glass-card"><h3>Últimos registros válidos</h3><?php foreach($q as $x): ?><div class="quality-line"><b><?= e($x['alberca']) ?></b><span>Cl <?= e($x['cloro_ppm']) ?> · pH <?= e($x['ph']) ?> · <?= e($x['temperatura_c']) ?>°C · <?= e(fdt($x['registrado_en'])) ?></span></div><?php endforeach; ?></section></div>
